queries.sparql:
PREFIX : <http://ambrosia.example.org/jobpostings#>
PREFIX p: <http://ambrosia.example.org/jobpostings/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?languagename WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:SE_LanguageID ?cg . ?child a :Languages ; p:LanguageID ?cg . ?l p:SE_Id ?pg . ?parent a :Software_Engineers ; p:EngineerID ?pg . } GROUP BY ?child }
  ?child p:LanguageName ?languagename .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Software_Engineers } }
  FILTER(?nf = ?total)
}

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/jobpostings#>
PREFIX p: <http://ambrosia.example.org/jobpostings/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  distributive: { SELECT ?name ?languagename WHERE {
  ?software_engineers_languages a :Software_Engineers_Languages .
  ?software_engineers a :Software_Engineers .
  ?software_engineers_languages p:hasSoftware_Engineers ?software_engineers .
  ?languages a :Languages .
  ?software_engineers_languages p:hasLanguages ?languages .
  ?software_engineers p:name ?name .
  ?languages p:LanguageName ?languagename .
} }
  collective: { SELECT ?languagename WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:SE_LanguageID ?cg . ?child a :Languages ; p:LanguageID ?cg . ?l p:SE_Id ?pg . ?parent a :Software_Engineers ; p:EngineerID ?pg . } GROUP BY ?child }
  ?child p:LanguageName ?languagename .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Software_Engineers } }
  FILTER(?nf = ?total)
} }
}
